content.newText:
#Requires -Version 5.1
<#
.SYNOPSIS
  Scaffold the daily learning session under 11_Learning (V2).

.DESCRIPTION
  Runs V2 pre-flight validation checks, then calls the learning-session CLI
  to create the session note, optional node stubs, connection stubs, project
  note, and weekly review from the terminal or Task Scheduler.

  V2 validation checks (run before every session):
    - Project scarcity: exactly one active project
    - Overdue mastery: notes past next_review_due by more than 7 days
    - Orphaned nodes: nodes with no connections after 7 days
    - Domain coverage: any domain with zero sessions in the last 14 days

.EXAMPLE
  # Bare session scaffold (just the session note)
  powershell scripts/learning-daily.ps1

  # Session + 3 node stubs
  powershell scripts/learning-daily.ps1 -Nodes "Supply Shock, Feedback Loop, Demand Destruction"

  # Session + nodes + connections
  powershell scripts/learning-daily.ps1 `
    -Nodes "Supply Shock, Feedback Loop" `
    -Connections "Supply Shock->Feedback Loop, Feedback Loop->Demand Destruction"

  # Full session with project and weekly review
  powershell scripts/learning-daily.ps1 `
    -Nodes "Rate Transmission, Housing Demand" `
    -Project "Housing Rate Transmission" `
    -TopicId macro-rate-transmission `
    -WeeklyReview

  # Skip pre-flight checks (not recommended)
  powershell scripts/learning-daily.ps1 -SkipValidation
#>
param(
  [string]$Date,
  [string]$Nodes,
  [string]$Connections,
  [string]$Project,
  [string]$TopicId,
  [switch]$WeeklyReview,
  [switch]$Force,
  [switch]$SkipValidation
)

$ErrorActionPreference = 'Stop'
$scriptsDir  = $PSScriptRoot
$vaultRoot   = Split-Path $scriptsDir -Parent
$learnRoot   = Join-Path $vaultRoot '11_Learning'
$today       = Get-Date

Set-Location $scriptsDir

# ─────────────────────────────────────────────────────────────────────────────
# V2 PRE-FLIGHT VALIDATION
# ─────────────────────────────────────────────────────────────────────────────

$warnings = @()
$errors   = @()

if (-not $SkipValidation) {
    Write-Host ''
    Write-Host '── V2 Pre-Flight Validation ──────────────────────────────' -ForegroundColor Cyan

    # ── Check 1: Project scarcity ─────────────────────────────────────────
    $projectDir   = Join-Path $learnRoot '07_Projects'
    $activeProjects = Get-ChildItem $projectDir -Filter '*.md' |
        Where-Object { $_.Name -ne '_Start Here.md' } |
        Where-Object { (Get-Content $_.FullName -Raw) -match 'project_status:\s*active' }

    if ($activeProjects.Count -eq 0) {
        $warnings += '[WARN] No active project found. Consider promoting one from the queue.'
    } elseif ($activeProjects.Count -gt 1) {
        $names = ($activeProjects | ForEach-Object { $_.BaseName }) -join ', '
        $errors += "[ERROR] $($activeProjects.Count) active projects found: $names — resolve before starting session."
    } else {
        Write-Host "  [OK] Active project: $($activeProjects[0].BaseName)" -ForegroundColor Green
    }

    # ── Check 2: Overdue mastery notes ───────────────────────────────────
    $masteryDir = Join-Path $learnRoot '05_Mastery'
    $overdueCount = 0
    $overdueNames = @()

    Get-ChildItem $masteryDir -Filter '*.md' |
        Where-Object { $_.Name -ne '_Start Here.md' } |
        ForEach-Object {
            $content = Get-Content $_.FullName -Raw
            if ($content -match 'next_review_due:\s*(\d{4}-\d{2}-\d{2})') {
                $dueDate = [datetime]::ParseExact($Matches[1], 'yyyy-MM-dd', $null)
                $overdueDays = ($today - $dueDate).Days
                if ($overdueDays -gt 7) {
                    $overdueCount++
                    $overdueNames += "$($_.BaseName) ($overdueDays days overdue)"
                }
            }
        }

    if ($overdueCount -gt 0) {
        $warnings += "[WARN] $overdueCount mastery note(s) overdue by 7+ days:"
        $overdueNames | ForEach-Object { $warnings += "       - $_" }
    } else {
        Write-Host '  [OK] No mastery notes critically overdue' -ForegroundColor Green
    }

    # ── Check 3: Orphaned nodes (no connections, created 7+ days ago) ─────
    $nodeDir = Join-Path $learnRoot '02_Nodes'
    $orphanCount = 0

    if (Test-Path $nodeDir) {
        Get-ChildItem $nodeDir -Filter '*.md' |
            Where-Object { $_.Name -ne '_Start Here.md' } |
            ForEach-Object {
                $ageDays = ($today - $_.CreationTime).Days
                if ($ageDays -ge 7) {
                    $content = Get-Content $_.FullName -Raw
                    # Check for empty connected_nodes array or missing connections
                    if ($content -match 'connected_nodes:\s*\[\]') {
                        $orphanCount++
                        $warnings += "[WARN] Orphaned node (no connections, $ageDays days old): $($_.BaseName)"
                    }
                }
            }
    }

    if ($orphanCount -eq 0) {
        Write-Host '  [OK] No orphaned nodes detected' -ForegroundColor Green
    }

    # ── Check 4: Domain coverage (last 14 days) ───────────────────────────
    $sessionDir = Join-Path $learnRoot '04_Sessions'
    $cutoff     = $today.AddDays(-14)
    $coveredDomains = @()

    Get-ChildItem $sessionDir -Filter '*.md' |
        Where-Object { $_.Name -ne '_Start Here.md' -and $_.LastWriteTime -ge $cutoff } |
        ForEach-Object {
            $content = Get-Content $_.FullName -Raw
            if ($content -match 'active_domain:\s*(.+)') {
                $coveredDomains += $Matches[1].Trim()
            }
        }

    $allDomains = @(
        'Economics/Markets', 'Math/Quant', 'Physics/Energy', 'Chemistry/Materials',
        'Biology/Life Systems', 'Technology/Software', 'Psychology/Behavior',
        'Sociology/Social Systems', 'Engineering/Infrastructure', 'Design/Systems Thinking',
        'Political Systems/Governance', 'History/Theory', 'Art/Creativity/Narrative',
        'Philosophy/Epistemology'
    )

    $neglectedDomains = $allDomains | Where-Object { $coveredDomains -notcontains $_ }
    if ($neglectedDomains.Count -gt 0) {
        $warnings += "[WARN] Domains with zero coverage in last 14 days: $($neglectedDomains -join ', ')"
    } else {
        Write-Host '  [OK] All domains covered in last 14 days' -ForegroundColor Green
    }

    # ── Print results ─────────────────────────────────────────────────────
    Write-Host ''

    if ($errors.Count -gt 0) {
        $errors | ForEach-Object { Write-Host $_ -ForegroundColor Red }
        Write-Host ''
        Write-Host 'Session blocked. Resolve errors above before continuing.' -ForegroundColor Red
        Write-Host 'Use -SkipValidation to override (not recommended).' -ForegroundColor DarkGray
        exit 1
    }

    if ($warnings.Count -gt 0) {
        $warnings | ForEach-Object { Write-Host $_ -ForegroundColor Yellow }
        Write-Host ''
        Write-Host 'Warnings noted. Session will continue.' -ForegroundColor DarkGray
    } else {
        Write-Host '  All checks passed.' -ForegroundColor Green
    }

    Write-Host '─────────────────────────────────────────────────────────' -ForegroundColor Cyan
    Write-Host ''
}

# ─────────────────────────────────────────────────────────────────────────────
# SESSION SCAFFOLD
# ─────────────────────────────────────────────────────────────────────────────

$nodeArgs = @('run.mjs', 'learning-session')

if ($Date)        { $nodeArgs += @('--date', $Date) }
if ($Nodes)       { $nodeArgs += @('--nodes', $Nodes) }
if ($Connections) { $nodeArgs += @('--connections', $Connections) }
if ($Project)     { $nodeArgs += @('--project', $Project) }
if ($TopicId)     { $nodeArgs += @('--topic-id', $TopicId) }
if ($WeeklyReview){ $nodeArgs += '--weekly-review' }
if ($Force)       { $nodeArgs += '--force' }

Write-Host ('-> node ' + ($nodeArgs -join ' ')) -ForegroundColor Gray
& node @nodeArgs

