  powershell scripts/learning-review.ps1
  powershell scripts/learning-review.ps1 -IncludeNodes
#>
param(
  [switch]$IncludeNodes
)

$ErrorActionPreference = 'Stop'
$vaultRoot  = Split-Path $PSScriptRoot -Parent
$learnRoot  = Join-Path $vaultRoot '11_Learning'
$today      = Get-Date

Write-Host ''
Write-Host '── Due Review Queue ──────────────────────────────────────' -ForegroundColor Cyan
Write-Host "   Date: $($today.ToString('yyyy-MM-dd'))" -ForegroundColor Gray
Write-Host ''

$dueItems = @()

# ── Scan mastery notes ────────────────────────────────────────────────────
$masteryDir = Join-Path $learnRoot '05_Mastery'
Get-ChildItem $masteryDir -Filter '*.md' |
    Where-Object { $_.Name -ne '_Start Here.md' } |
    ForEach-Object {
        $content = Get-Content $_.FullName -Raw
        if ($content -match 'next_review_due:\s*(\d{4}-\d{2}-\d{2})') {
            $dueDate = [datetime]::ParseExact($Matches[1], 'yyyy-MM-dd', $null)
            if ($dueDate -le $today) {
                $overdueDays = ($today - $dueDate).Days
                $failCount = 0
                if ($content -match 'retrieval_failure_count:\s*(\d+)') { $failCount = [int]$Matches[1] }
                $domain = ''
                if ($content -match 'domain::\s*(.+)') { $domain = $Matches[1].Trim() }
                $level = 0
                if ($content -match 'level::\s*(\d+)') { $level = [int]$Matches[1] }
                $dueItems += [PSCustomObject]@{
                    Type        = 'Mastery'
                    Name        = $_.BaseName
                    Domain      = $domain
                    Level       = $level
                    DueDate     = $Matches[1]
                    OverdueDays = $overdueDays
                    Failures    = $failCount
                    Path        = $_.FullName
                }
            }
        }
    }

# ── Scan nodes (optional) ─────────────────────────────────────────────────
if ($IncludeNodes) {
    $nodeDir = Join-Path $learnRoot '02_Nodes'
    if (Test-Path $nodeDir) {
        Get-ChildItem $nodeDir -Filter '*.md' |
            Where-Object { $_.Name -ne '_Start Here.md' } |
            ForEach-Object {
                $content = Get-Content $_.FullName -Raw
                if ($content -match 'next_review_due:\s*(\d{4}-\d{2}-\d{2})') {
                    $dueDate = [datetime]::ParseExact($Matches[1], 'yyyy-MM-dd', $null)
                    if ($dueDate -le $today) {
                        $overdueDays = ($today - $dueDate).Days
                        $failCount = 0
                        if ($content -match 'retrieval_failure_count:\s*(\d+)') { $failCount = [int]$Matches[1] }
                        $domain = ''
                        if ($content -match 'primary_domain:\s*(.+)') { $domain = $Matches[1].Trim() }
                        $dueItems += [PSCustomObject]@{
                            Type        = 'Node'
                            Name        = $_.BaseName
                            Domain      = $domain
                            Level       = 0
                            DueDate     = $Matches[1]
                            OverdueDays = $overdueDays
                            Failures    = $failCount
                            Path        = $_.FullName
                        }
                    }
                }
            }
    }
}

# ── Sort and display ──────────────────────────────────────────────────────
$sorted = $dueItems | Sort-Object -Property @{E='OverdueDays'; D=$true}, @{E='Failures'; D=$true}

if ($sorted.Count -eq 0) {
    Write-Host '  No items due today. Queue is clear.' -ForegroundColor Green
} else {
    Write-Host "  $($sorted.Count) item(s) due — retrieve from memory before opening notes." -ForegroundColor Yellow
    Write-Host ''
    $i = 1
    foreach ($item in $sorted) {
        $overdueLabel = if ($item.OverdueDays -gt 0) { " (+$($item.OverdueDays)d overdue)" } else { '' }
        $failLabel    = if ($item.Failures -gt 0) { " [⚠ $($item.Failures) prior failures]" } else { '' }
        $color = if ($item.OverdueDays -gt 7) { 'Red' } elseif ($item.OverdueDays -gt 0) { 'Yellow' } else { 'White' }
        Write-Host "  $i. [$($item.Type)] $($item.Name) — $($item.Domain)$overdueLabel$failLabel" -ForegroundColor $color
        $i++
    }
}

Write-Host ''
Write-Host '─────────────────────────────────────────────────────────' -ForegroundColor Cyan
Write-Host ''
Write-Host 'Tip: Answer each prompt from memory. Score before opening the note.' -ForegroundColor DarkGray
Write-Host ''

