#Requires -Version 5.1
<#
.SYNOPSIS
  Scan 11_Learning for broken wikilinks and update Link_Integrity_Report.md.

.DESCRIPTION
  Walks all markdown files under 11_Learning/, extracts wikilinks ([[...]]),
  and checks whether the target note exists in the vault. Reports:
    - Broken links (target not found)
    - Absolute-path links (should be short wikilinks)
    - Empty scaffold folders

  Appends a dated scan summary to Link_Integrity_Report.md.

.EXAMPLE
  powershell scripts/learning-link-audit.ps1
  powershell scripts/learning-link-audit.ps1 -Verbose
#>
param(
  [switch]$Verbose
)

$ErrorActionPreference = 'Stop'
$vaultRoot   = Split-Path $PSScriptRoot -Parent
$learnRoot   = Join-Path $vaultRoot '11_Learning'
$reportPath  = Join-Path $learnRoot '00_Dashboard\Link_Integrity_Report.md'
$today       = Get-Date

Write-Host ''
Write-Host '── Link Audit ────────────────────────────────────────────' -ForegroundColor Cyan
Write-Host "   Scanning: $learnRoot" -ForegroundColor Gray
Write-Host ''

# Build index of all note names in the vault
$allNotes = Get-ChildItem $vaultRoot -Recurse -Filter '*.md' |
    ForEach-Object { $_.BaseName.ToLower() }
$noteSet = @{}
$allNotes | ForEach-Object { $noteSet[$_] = $true }

$broken    = @()
$absPaths  = @()
$emptyFolders = @()

# ── Scan for broken wikilinks ─────────────────────────────────────────────
Get-ChildItem $learnRoot -Recurse -Filter '*.md' | ForEach-Object {
    $file    = $_
    $content = Get-Content $file.FullName -Raw
    $relPath = $file.FullName.Replace($learnRoot + '\', '')

    # Extract all [[...]] links
    $links = [regex]::Matches($content, '\[\[([^\]|#]+)') | ForEach-Object { $_.Groups[1].Value.Trim() }

    foreach ($link in $links) {
        # Check for absolute paths
        if ($link -match '^[A-Za-z]:\\|^My_Data/|^\d{2}_') {
            $absPaths += [PSCustomObject]@{ File = $relPath; Link = $link }
            continue
        }

        # Normalize: strip path separators, get base name
        $baseName = ($link -split '[/\\]')[-1].ToLower()
        $baseName = $baseName -replace '\.\w+$', ''  # remove extension if present

        if (-not $noteSet.ContainsKey($baseName)) {
            $broken += [PSCustomObject]@{ File = $relPath; Link = $link }
            if ($Verbose) { Write-Host "  BROKEN: $relPath -> [[$link]]" -ForegroundColor Red }
        }
    }
}

# ── Check for empty scaffold folders ─────────────────────────────────────
$foldersToCheck = @('02_Nodes', '03_Connections', 'Learner_Notebooks')
foreach ($folder in $foldersToCheck) {
    $folderPath = Join-Path $learnRoot $folder
    if (Test-Path $folderPath) {
        $files = Get-ChildItem $folderPath -Filter '*.md' | Where-Object { $_.Name -ne '_Start Here.md' }
        if ($files.Count -eq 0) {
            $emptyFolders += $folder
        }
    }
}

# ── Display results ───────────────────────────────────────────────────────
Write-Host "  Broken links:     $($broken.Count)" -ForegroundColor $(if ($broken.Count -gt 0) { 'Yellow' } else { 'Green' })
Write-Host "  Absolute paths:   $($absPaths.Count)" -ForegroundColor $(if ($absPaths.Count -gt 0) { 'Yellow' } else { 'Green' })
Write-Host "  Empty folders:    $($emptyFolders.Count)" -ForegroundColor $(if ($emptyFolders.Count -gt 0) { 'Yellow' } else { 'Green' })

if ($broken.Count -gt 0) {
    Write-Host ''
    Write-Host '  Broken link details:' -ForegroundColor Yellow
    $broken | ForEach-Object { Write-Host "    $($_.File) -> [[$($_.Link)]]" -ForegroundColor DarkYellow }
}

# ── Append scan summary to report ────────────────────────────────────────
$scanEntry = @"

---

## Scan: $($today.ToString('yyyy-MM-dd HH:mm'))

| Category | Count |
|----------|-------|
| Broken wikilinks | $($broken.Count) |
| Absolute path links | $($absPaths.Count) |
| Empty scaffold folders | $($emptyFolders.Count) |

"@

if ($broken.Count -gt 0) {
    $scanEntry += "`n### Broken Links`n`n| Source | Broken Link |`n|--------|-------------|`n"
    $broken | ForEach-Object { $scanEntry += "| ``$($_.File)`` | ``[[$($_.Link)]]`` |`n" }
}

if ($emptyFolders.Count -gt 0) {
    $scanEntry += "`n### Empty Folders`n`n"
    $emptyFolders | ForEach-Object { $scanEntry += "- ``$_/``  — no content yet`n" }
}

Add-Content -Path $reportPath -Value $scanEntry -Encoding UTF8

Write-Host ''
Write-Host "  Report updated: $reportPath" -ForegroundColor Gray
Write-Host '─────────────────────────────────────────────────────────' -ForegroundColor Cyan
Write-Host ''

