async function handleOverview(res, paths) {
  const today = todayStr();
  const sessionNote = await findSessionNote(paths, today);
  const masteryNotes = await loadAllMastery(paths);

  const summary = { active: 0, complete: 0, locked: 0, total: 0 };
  const dueItems = [];
  let recommended = null;

  for (const note of masteryNotes) {
    summary.total++;
    const state = note.inlineFields.progress_state || '';
    if (state === 'active') summary.active++;
    else if (state === 'complete') summary.complete++;
    else if (state === 'locked') summary.locked++;

    // Build V2 due review queue
    const dueDate = note.inlineFields.next_review_due || '';
    if (dueDate && dueDate <= today) {
      const overdueDays = Math.max(0, Math.floor((new Date(today) - new Date(dueDate)) / 86400000));
      dueItems.push({
        topic_id: note.inlineFields.topic_id,
        domain: note.inlineFields.domain,
        level: Number(note.inlineFields.level) || 0,
        next_review_due: dueDate,
        overdue_days: overdueDays,
        retrieval_failure_count: Number(note.inlineFields.retrieval_failure_count) || 0,
        active_mode: note.inlineFields.active_mode || 'review',
        next_action: note.inlineFields.next_action || '',
      });
    }

    // Recommend overdue first, otherwise first active
    if (!recommended && (state === 'active' || dueDate <= today)) {
      recommended = {
        topic_id: note.inlineFields.topic_id,
        domain: note.inlineFields.domain,
        next_action: note.inlineFields.next_action,
        level: note.inlineFields.level,
      };
    }
  }

  // Sort due items: most overdue first, then by failure count
  dueItems.sort((a, b) => b.overdue_days - a.overdue_days || b.retrieval_failure_count - a.retrieval_failure_count);

  // Project conflict check
  const projectFiles = await loadAllProjects(paths);
  const activeProjects = projectFiles.filter(p => p.data.project_status === 'active');

  // Graph activity: files created in last 7 days
  const nodesThisWeek = await countRecentFiles(paths.nodes, 7);
  const connectionsThisWeek = await countRecentFiles(paths.connections, 7);

  const streak = await calculateStreak(paths);

  sendJson(res, {
    today_session: sessionNote
      ? {
          date: today,
          nodes_created: sessionNote.inlineFields.nodes_created,
          connections_created: sessionNote.inlineFields.connections_created,
          mode: sessionNote.inlineFields.mode || sessionNote.data.mode || 'daily-engine',
          friction_score: sessionNote.inlineFields.friction_score,
          active_project: sessionNote.inlineFields.project_touched || sessionNote.inlineFields.active_project || sessionNote.data.active_project,
        }
      : null,
    mastery_summary: summary,
    recommended_next: recommended,
    streak,
    due_review_queue: dueItems,
    project_conflict: activeProjects.length > 1,
    active_project_count: activeProjects.length,
    graph_activity: {
      nodes_this_week: nodesThisWeek,
      connections_this_week: connectionsThisWeek,
    },
  });
}

