  }

  const today = new Date().toISOString().slice(0, 10);

  const rows = items.map((item) => {
    const topicId = item.topic_id || item.id || '';
    const level = item.level ?? 0;
    const confidence = item.confidence ?? 0;
    const isDue = item.next_review_due && item.next_review_due <= today;
    const dueCellStyle = isDue
      ? 'color:var(--color-warning,#f59e0b);font-weight:600;'
      : 'color:var(--color-muted)';
    const successCount = item.retrieval_success_count ?? '—';
    const failureCount = item.retrieval_failure_count ?? '—';

    return `
      <tr data-topic-id="${topicId}" style="cursor:pointer">
        <td>${item.topic || item.title || topicId}</td>
        <td>${item.domain || '—'}</td>
