        <td>${confidenceBarHTML(confidence, 100)}</td>
        <td style="${dueCellStyle}">${item.next_review_due || '—'}</td>
        <td style="font-size:11px;color:var(--color-muted)">${successCount}✓ ${failureCount}✗</td>
